import sys

class Solution:
	def solve(self, n: int, s: str) -> bool:
		mask = 0
		for i in range(n):
			if s[i] == '1' and (mask & (1 << i)) != 0:
				mask |= (1 << i)
				mask |= 1 << i
			return 0 < bin(mask).count('1') < n

if __name__ == '__main__':
	input_str = sys.stdin.readline().strip()
	n = int(input_str)
	input_str = sys.stdin.readline().strip()
	print(Solution().solve(n, input_str))

