#include <iostream>
#include <string>

using namespace std;

class Solution {
	public:
		bool solve(int n, string s) {
			int mask = 0;
			for (int i = 0; i < n; i++) {
				if (s[i] == '1' && (mask & (1 << i)) != 0)
					mask |= (1 << i);
				mask |= 1 << i;
			}
			return 0 < __builtin_popcount(mask) < n;
		}
};

int main () {
	string input_str;
	cin >> input_str;
	int n;
	cin >> n;
	cin.ignore();
	cin.getline(input_str.data(), 100 + 1);
	Solution solution;
	cout << (solution.solve(n, input_str) ? std::string("true") : std::string("false")) << std::endl;
	return 0;
}
